import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,r as s,t as c}from"./chunks/javadoc.By8MmAW1.js";const l=JSON.parse(`{"title":"在 IntelliJ IDEA 中生成源代码","description":"在 IntelliJ IDEA 中生成 Minecraft 源代码的指南。","frontmatter":{"title":"在 IntelliJ IDEA 中生成源代码","description":"在 IntelliJ IDEA 中生成 Minecraft 源代码的指南。","authors":["dicedpixels"],"prev":{"text":"在 IntelliJ IDEA 中启动游戏","link":"./launching-the-game"},"next":{"text":"在 IntelliJ IDEA 中构建模组","link":"./building-a-mod"},"files":[]},"headers":[],"relativePath":"zh_cn/develop/getting-started/intellij-idea/generating-sources.md","filePath":"translated/zh_cn/develop/getting-started/intellij-idea/generating-sources.md","lastUpdated":1772272927000}`);var u={name:`zh_cn/develop/getting-started/intellij-idea/generating-sources.md`};function d(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 IntelliJ IDEA 中生成源代码 <a class="header-anchor" href="#h1" aria-label="Permalink to “在 IntelliJ IDEA 中生成源代码”">​</a></h1><p>Fabric 工具链允许你通过在本地生成 Minecraft 源代码来访问它，并且你可以使用 IntelliJ IDEA 方便地浏览它。 要生成源代码，你需要运行 <code>genSources</code> Gradle 任务。</p><p>这可以通过在 Gradle 面板中运行 <strong>Tasks</strong> &gt; <strong><code>fabric</code></strong> 下的 <code>genSources</code> 任务来完成： <img src="/assets/develop/getting-started/intellij/gradle-gensources.png" alt="Gradle 面板中的 genSources 任务" loading="lazy"></p><p>或者，你也可以从终端运行以下命令：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genSources</span></span></code></pre></div><p><img src="/assets/develop/getting-started/intellij/terminal-gensources.png" alt="终端中的 genSources 任务" loading="lazy"></p><h2 id="attaching-sources" tabindex="-1">附加源代码 <a class="header-anchor" href="#attaching-sources" aria-label="Permalink to “附加源代码”">​</a></h2><p>IntelliJ 需要额外一步将生成的源代码附加到项目。</p><p>要这样做，请打开任意 Minecraft 类。 你可以按 <kbd>Ctrl</kbd> + 单击转到定义，从而打开类或使用“Search everywhere”来打开类。</p><p>我们打开 <code>MinecraftServer.class</code> 举例。 你现在应该会看到顶部有一个蓝色横幅，上面有个“<strong>Choose Sources...</strong>”链接。</p><p><img src="/assets/develop/getting-started/intellij/choose-sources.png" alt="选择源代码" loading="lazy"></p><p>单击“Choose Sources...”打开文件选择器对话框。 默认情况下，此对话框将在生成源代码的正确位置打开。</p><p>选择以 <strong><code>-sources</code></strong> 结尾的文件，然后单击<strong>打开</strong>确认选择。</p><p><img src="/assets/develop/getting-started/intellij/choose-sources-dialog.png" alt="选择源代码对话框" loading="lazy"></p><p>你现在应该可以搜索参考了。 如果你使用的是包含 Javadoc 的映射集，例如 <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a>（用于 Mojang 映射）或 Yarn，你现在也应该可以看到 Javadoc。</p><p><img src="/assets/develop/getting-started/intellij/javadoc.png" alt="源代码中的 Javadoc 注释" loading="lazy"></p>`,16)]])}var f=r(u,[[`render`,d]]);export{l as __pageData,f as default};